class Solution:
    def maxScore(self, grid):
        m, n = len(grid), len(grid[0])
        best = float('-inf')
        for r in range(m):
            for c in range(n):
                for r0 in range(r + 1):
                    for c0 in range(c + 1):
                        if r0 == r and c0 == c:
                            continue
                        best = max(best, grid[r][c] - grid[r0][c0])
        return best

