class Solution:
    def maxScore(self, grid):
        m, n = len(grid), len(grid[0])
        # dp_min[r][c] = min value reachable to reach (r,c) from top-left
        INF = float('inf')
        dp = [[INF] * n for _ in range(m)]
        dp[0][0] = grid[0][0]
        for c in range(1, n):
            dp[0][c] = min(dp[0][c-1], grid[0][c])
        for r in range(1, m):
            dp[r][0] = min(dp[r-1][0], grid[r][0])
        for r in range(1, m):
            for c in range(1, n):
                dp[r][c] = min(dp[r-1][c], dp[r][c-1], grid[r][c])
        best = float('-inf')
        for r in range(m):
            for c in range(n):
                # score of moving TO (r,c) from some earlier cell
                if r == 0 and c == 0:
                    continue
                min_prev = dp[r-1][c] if r > 0 else INF
                if c > 0:
                    min_prev = min(min_prev, dp[r][c-1])
                best = max(best, grid[r][c] - min_prev)
        return best

