var maxScore = function(grid) {
    const m = grid.length, n = grid[0].length;
    const INF = Infinity;
    const dp = Array.from({length: m}, () => new Array(n).fill(INF));
    dp[0][0] = grid[0][0];
    for (let c = 1; c < n; c++) dp[0][c] = Math.min(dp[0][c-1], grid[0][c]);
    for (let r = 1; r < m; r++) dp[r][0] = Math.min(dp[r-1][0], grid[r][0]);
    for (let r = 1; r < m; r++) {
        for (let c = 1; c < n; c++) {
            dp[r][c] = Math.min(dp[r-1][c], dp[r][c-1], grid[r][c]);
        }
    }
    let best = -Infinity;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (r === 0 && c === 0) continue;
            let minPrev = r > 0 ? dp[r-1][c] : INF;
            if (c > 0) minPrev = Math.min(minPrev, dp[r][c-1]);
            best = Math.max(best, grid[r][c] - minPrev);
        }
    }
    return best;
};
